script:
window.checkIn = function() {
   if(!navigator.geolocation){
       frappe.msgprint("Geolocation is not supported by your browser");
   }

   navigator.geolocation.getCurrentPosition( function(position){

       frappe.call({
           method: "employee_self_service.api.get_location",
           args: {
               latitude: position.coords.latitude,
               longitude: position.coords.longitude,
           },
           callback: function(res) {
               frappe.msgprint(res.message)
           }
       })
   })
 }

window.checkOut = function() {
   if(!navigator.geolocation){
       frappe.msgprint("Geolocation is not supported by your browser");
   }

   navigator.geolocation.getCurrentPosition( function(position){

       frappe.call({
           method: "employee_self_service.api.handle_checkout",
           args: {
               latitude: position.coords.latitude,
               longitude: position.coords.longitude,
           },
           callback: function(res) {
               frappe.msgprint(res.message)
           }
       })
   })
 }

style:
html,
   body {
       margin: 0;
       font-family: 'Inter', sans-serif;
   }

   .container {
       display: flex;
   }

   .main {
       width: 90%;
       padding: 30px 20px;
       border-radius: 16px;
   }

   .title h1 {
       margin-bottom: 10px;
       font-size: 28px;
   }

   .content p {
       margin-bottom: 25px;
       color: #64748b;
       display: flex;
   }

   button {
       padding: 12px;
       margin: 10px 0;
       border: none;
       border-radius: 8px;
       font-size: 16px;
       font-weight: 600;
       cursor: pointer;
       transition: 0.3s ease;
   }

   .check-in {
       background: linear-gradient(135deg, rgb(231, 241, 239), rgb(216, 219, 229));
       color: black;
   }

   .check-out {
       background: linear-gradient(135deg, rgb(231, 241, 239), rgb(216, 219, 229));
       color: black;
   }
